"""
Standalone patch — writes mkt-context for Isaiah 14-18 directly.
Run: python3 scripts/zc-context-isaiah-14-18-patch.py
Chapters: 14 (32v), 15 (9v), 16 (14v), 17 (14v), 18 (7v) = 76 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "14": {
    "1": "<p>'For the LORD will show compassion to Jacob and once again choose Israel, and will settle them in their own land. Foreigners will join them and attach themselves to the house of Jacob' — the introductory prose oracle (14:1-3) situating the taunt song of vv.4-21 within the framework of Israel's restoration. The two covenant concepts: racham (show compassion, the tender parental mercy of the covenant) and bachar (choose, the election vocabulary) re-applied after the exile's discipline. The ingathering of foreigners (nilvah hagger, the stranger who joins/attaches himself) connects to 56:3-7 (foreigners who bind themselves to YHWH), 60:3-7 (nations flowing to Zion's light), and Zech 2:11 ('many nations will be joined with the LORD in that day'). The restoration oracle frames the taunt song: the taunt can be pronounced because Israel's future is secure.</p>",
    "2": "<p>'Peoples will escort them back to their homeland; the house of Israel will possess them as servants in the LORD's land. They will take captive those who once held them captive and rule over those who once oppressed them' — the reversal of the captivity: the nations that transported Israel into exile (Babylon, Assyria, and their client states) will transport Israel home. The specific reversal: 'they will take captive those who took them captive' (venihyu shavehem lishvuyim) — the former slave-masters becoming servants. This is not ethnic revenge but covenantal vindication — the covenant curses of Deut 28:41 ('your sons and daughters will be taken captive') reversed by covenantal restoration. The language echoes the Exodus: Israel in Egypt as slaves, then the Egyptians stripped of their wealth at the departure (Exod 12:35-36).</p>",
    "3": "<p>'On the day when the LORD gives you rest from your pain and suffering and from the cruel servitude you were forced to endure' — the rest oracle: YHWH giving nuach (rest/settling) from toil, pain, and 'cruel servitude' (avodah qasha, the hard/harsh service — the same term as the Egyptian bondage in Exod 1:14: 'they made their lives bitter with harsh service'). The exile as a new Egypt is the controlling analogy for the restoration-from-Babylon theology of chs. 40-55. The 'day' of YHWH's giving rest is the eschatological day when judgment is completed and the restored community lives in security.</p>",
    "4": "<p>'You will take up this song of mockery against the king of Babylon' — the mashal (v4: tissa el-melech bavel, you will take up this proverb/taunt song against the king of Babylon). Mashal covers several related senses: proverb, parable, taunt song. The taunt song (mocking elegy) was a recognized literary form in the ANE — the Babylonian 'Dialogue of Pessimism' and Egyptian satire texts are related genres. The king of Babylon is not identified — the oracle applies to the type of the proud conqueror and accumulates historical resonances: Sargon II (who died in battle without burial, 705 BCE, which was interpreted as divine rejection), Sennacherib (murdered by his sons), Nebuchadnezzar (struck with madness, Dan 4). 'How the tyrant has come to his end! How his insolent fury is over!' (echad nagas, the taskmaster has ceased; shavat zahav, the golden city has ceased) — the two great attributes of Babylonian power dissolved.</p>",
    "5": "<p>'The LORD has shattered the rod of the wicked, the sceptre of rulers' — the two instruments of imperial power: matteh risha'im (rod of the wicked) and shevet moshlim (staff of rulers). The rod and staff are the Assyrian/Babylonian symbols of military discipline and conquered-territory governance (the same rod as 9:4 'the rod of his oppressor'). YHWH as the active shattering agent: he shavar (breaks/shatters) what seemed indestructible. The rod of the wicked is the same rod YHWH himself wielded through Assyria (10:5: 'rod of my anger') — now he breaks the rod after using it. The instrument of divine discipline is not eternal; it lasts only as long as the disciplinary purpose is served.</p>",
    "6": "<p>'The rod that beat down peoples in furious, relentless blows, that kept nations under the heel of tyranny without relief' — the rod's specific mode of operation described: makkeh ammim be'evrah (striking peoples in fury/rage), makkat bilti-sariot (a blow without cessation — the relentless quality). The 'heel of tyranny' (radah vagoyim bemirshat, ruling over nations in pursuit — driving them like cattle). The Assyrian and Babylonian military campaigns are described in their own annals in exactly this vocabulary: relentless pursuit, total subjugation, no respite. The annals of Tiglath-Pileser III, Sargon II, Sennacherib, and Nebuchadnezzar all record the systematic reduction of conquered peoples to labor pools and tribute sources.</p>",
    "7": "<p>'The whole earth rests quietly in peace; they burst into song' — the ecological consequence of the tyrant's fall: kol-ha'arets shaqtah shaletah (all the earth is at rest, it has been quiet) and patschu berinah (they have burst into song/exultation). The silence and song after tyranny's removal is the contrast to the roaring and crashing of the military advance (cf. 17:12-14). The earth itself participates in the response to divine victory — the personified creation celebrates the end of imperial oppression. Romans 8:19-22 gives theological depth to creation's waiting for liberation from the bondage brought by human sin and violence.</p>",
    "8": "<p>'The very cypress trees rejoice over you, as do the cedars of Lebanon: Since you have been brought low, no axeman has risen against us' — the trees of Lebanon join the celebration. The cedars of Lebanon were the most prized timber in the ANE — used for palace and temple construction. Assyrian and Babylonian kings systematically logged Lebanon's forests for their building projects (Sennacherib's palace annals record thousands of cedar beams). The trees' 'speech' is personification: 'since you were laid down, no woodcutter has come up against us' (lo ya'aleh hakoret aleinu). The ecological restoration — the forests no longer stripped for imperial building — is a concrete consequence of the empire's end. The cedar-rejoicing mirrors Ps 96:12 ('let the trees of the forest sing for joy') and anticipates the eschatological creation-restoration of 11:6-9.</p>",
    "9": "<p>'Sheol below stirs itself to meet you at your arrival; it rouses the spirits of the dead — all who were rulers of the earth; it lifts every king of the nations from their thrones' — the Sheol reception scene: the underworld (She'ol min-tachat, Sheol from beneath) is portrayed as agitated at the arrival of the great tyrant. The rephaim (spirits/shades of the dead — the weak, diminished existence of the dead in the ANE underworld) are roused to greet the newcomer. The kings of the nations — all the great rulers who preceded him in death — are 'lifted' from their thrones (qam mikisei'otam, risen from their thrones) to meet him. The irony is that the man who once raised himself above all kings (v13-14) is now reduced to meeting the ghosts of kings. In Canaanite and Mesopotamian conception, Sheol was a place of diminished existence but maintained some social stratification — kings retained a shadowy royal status.</p>",
    "10": "<p>'They will all speak up and say to you: You too have been brought to nothing, just as we were — you are exactly like us!' — the dead kings' taunt: 'gam-attah challotah kamonu, elenu nimmashalta' (you too have become weak as we; you have become like us). The great leveling of death: the man who claimed divine status ('I will become like the Most High,' v14) is now told 'you are exactly like us' — a mere shade in Sheol like every other dead person. The ancient hubris-nemesis pattern: the person who most claimed to transcend ordinary human limitation is shown to be maximally ordinary in death. Ecclesiastes 9:2 makes the same leveling observation: 'the same destiny overtakes all.'</p>",
    "11": "<p>'Your magnificence has been dragged down to Sheol — the music of your harps along with it. Maggots are spread beneath you as your mattress, and worms are your blanket' — the tyrant's luxury in death replaced by the luxuries of the grave: the 'magnificence' (gaonkha, your pride/excellence) dragged down (hored, brought low — the same word as 'brought low' in v12, 15) along with the music of harps (dimrat nevalekha, the noise of your lutes). The royal court's musical entertainment (cf. Amos 6:5: the wealthy lie on beds playing on harps) follows the king into death but is equally useless. The mattress and blanket of maggots (rimah) and worms (tola'ah) — the biological reality of decomposition described with the language of luxurious bedding.</p>",
    "12": "<p>'How you have fallen from heaven, O Day Star, son of the Dawn! You have been hurled to the ground — you who laid nations prostrate!' — the iconic 'fallen star' verse: eikh nafalta min-hashamayim helel ben-shachar (how you have fallen from heaven, O shining one, son of the dawn!). Helel ben Shachar ('shining one, son of dawn') is the Hebrew name of the morning star (Venus as the pre-dawn brightest star), which in Canaanite myth was a divine being. The Latin Vulgate renders helel as 'Lucifer' (light-bearer), which became the standard Christian name for Satan based on Jesus's statement in Luke 10:18 ('I saw Satan fall like lightning from heaven'). In immediate context, the metaphor describes the Babylonian king's ambition and fall; in the broader canonical context, it becomes associated with the primordial fall of the adversary. 'Who laid nations prostrate' (cholesh al-goyim, who weakened/prostrated the nations) — the tyrant's achievement of world domination used as the foil for the astonishing reversal.</p>",
    "13": "<p>'For you said in your heart: I will climb up to heaven; I will set my throne higher than the stars of God; I will sit enthroned on the mount of assembly, in the far north' — the five 'I will' boasts: (1) ascending to heaven, (2) throne above the stars of El, (3) enthroned on the mount of assembly (har-mo'ed, the divine assembly mountain) in the far north (yarketei tsaphon, the extreme parts of Zaphon). 'Mount Zaphon' (from tsaphon = north) is the Canaanite divine mountain where Baal held his divine council, equivalent to the Greek Olympus. In the Ugaritic Baal Cycle, the divine assembly convenes on Mount Zaphon. The king's ambition is to take Baal's place on the divine assembly mountain — to usurp the seat of divine governance. This hubris-claim against the divine council order recurs in Ezek 28:2 (the prince of Tyre: 'I am a god; I sit on the throne of a god').</p>",
    "14": "<p>'I will rise above the topmost layers of cloud; I will become like the Most High' — the fifth and culminating 'I will' boast: 'e'adeh le'Elyon, I will become like the Most High.' Elyon (the Most High) is one of God's ancient titles (Gen 14:18-20: Melchizedek priest of El Elyon; Ps 47:2: YHWH the Most High). The boast of equivalence or identity with the Most High is the ultimate transgression of the creator-creature distinction. The five 'I will' boasts create an escalating climax: each is more audacious than the last, ascending from 'I will rise to heaven' (spatial movement) to 'I will become like God' (ontological equivalence). This pattern of self-deification is the defining mark of the 'man of lawlessness' in 2 Thess 2:4 ('He will oppose and exalt himself above everything that is called God or is worshiped').</p>",
    "15": "<p>'But you have been brought down to Sheol, to the deepest depths of the pit' — the great reversal stated with maximum economy after the five-fold 'I will ascend' boasts: ach el-she'ol turad el-yarketei-vor (but to Sheol you have been brought down, to the depths of the pit). The reversal is absolute: the one who said 'I will ascend above the heights of the clouds' (v14) is thrust to the 'deepest depths of the pit' (el-yarketei-vor = the extreme depths/recesses of the cistern/pit). The vocabulary of extreme reversal — heights vs. depths — is the defining structure of the taunt. Ezekiel 26:20 uses the same vocabulary for the judgment on Tyre: 'I will bring you down with those who go into the pit, to the depths of the earth.' Jesus's language in Matt 11:23 ('You, Capernaum, will you be lifted up to the heavens? No, you will go down to Hades') echoes this reversal pattern.</p>",
    "16": "<p>'Those who see you will scrutinize you and consider: Is this really the man who made the earth shake, who rattled kingdoms' — the startled recognition of bystanders: the ones 'who see' (ro'eka, those who see you) will 'scrutinize' (yitbonenu, will look carefully, study intensely) the fallen tyrant. The rhetorical question: 'Is this the man (ha-ish, is it the man) who made the earth tremble (hirgish ha'arets), who shook kingdoms (hirish mamlakhot)?' The contrast between past greatness (earth-shaking, kingdom-rattling power) and present reduction (a corpse in Sheol, no burial) is the taunt's core. The 'ha-ish' (the man!) is a mocking emphasis — just a man, after all the divine claims. The same mockery of hubris reduced to bare humanity appears in Ezek 28:9 ('will you still say \"I am a god\" in the presence of those who slay you? You are only a man, not a god').</p>",
    "17": "<p>'Who turned the whole world into a wasteland and demolished its cities, who never released his prisoners to go home?' — the tyrant's specific crimes: (1) turning the world (tevel, the inhabited earth) into a wasteland/desert (midbar, the wilderness); (2) demolishing cities (arav ereha, breaking down its cities); (3) never releasing prisoners (asiraiv lo patach baytah, his prisoners he did not open homeward). The third charge is particularly significant: the 'release of prisoners' was a royal duty in the ANE — at accession, kings would issue amnesty decrees releasing captives. The Cyrus Cylinder records Cyrus's policy of releasing captives and returning them to their homelands, which is the specific counter-example. Babylon's king never opened the prison gate — Cyrus opened it for all peoples including the Jews.</p>",
    "18": "<p>'All the kings of the nations lie in state, each in his own burial place' — the contrast with proper royal burial: all the other kings (kol-malkei goyim) lie in honor (shakhvu bekavod, lie in glory/honor), each in his own burial house (ish beveito). The proper royal burial in the ANE was essential for the deceased's wellbeing in the afterlife — the great kings of Assyria and Babylon had elaborate tombs prepared. Sennacherib's murder by his sons (2 Kgs 19:37; Isa 37:38) was a catastrophe partly because of the disruption to proper burial arrangements. The contrast between the honored dead kings and the dishonored Babylonian king (thrown out, v19) is the social reversal at its most pointed.</p>",
    "19": "<p>'But you are thrown out of your grave like a rejected branch — surrounded by the bodies of those cut down by the sword, who sink to the rocky pit like a carcass trampled underfoot' — the three images of dishonor: (1) 'rejected branch' (netser nit'av, a despised/abominable shoot) — the cutting that is thrown away rather than planted; (2) surrounded by sword-pierced bodies; (3) 'like a carcass trampled underfoot' (kepeger muvus, like a trampled carcass). To be denied burial was the ultimate humiliation in the ancient world — the body exposed to scavenging birds and animals rather than enclosed in a house (Deut 28:26: covenant curse — 'your corpse will be food for all the birds and beasts'). The historical resonance: Sargon II of Assyria died in battle in 705 BCE without his body being recovered, which was widely understood as divine rejection. The oracle's force: the Babylonian king will suffer what Sargon suffered.</p>",
    "20": "<p>'You will never be buried with them, because you destroyed your own country and murdered your own people. The seed of evildoers will never again be mentioned' — the grounds for the denial of burial: 'you destroyed your own land and murdered your own people' (ki artsa shachatta amkha harag'ta, for your land you ruined, your people you killed). The specific charge of destroying 'your own' land and people — the tyrant's crimes against his own subjects rather than only against foreign peoples — adds a dimension of self-destruction to the judgment. 'The seed of evildoers will never be mentioned' (lo-yiqqare le'olam zara mere'im) — the dynastic annihilation: no future reference to this evil lineage. In ANE culture, to be 'remembered' (zachor) was to continue having an effect on the living; to be 'unmentioned' was a second death beyond physical death.</p>",
    "21": "<p>'Ready the execution ground for his sons on account of their fathers' guilt — so that they never rise to possess the land and overrun the face of the earth with cities' — the dynastic judgment extended to the sons: the execution ground (mivtach, slaughter-place) prepared for the royal sons. The rationale: 'lest they rise and possess the land and fill the face of the world with cities' (male penei-tevel arim) — the dynastic cycle of empire-building (city construction is the sign of imperial power in Genesis: Nimrod builds Babel, Nineveh, etc.) must be broken by dynastic elimination. This reflects the ANE practice of eliminating rival claimants at the fall of a dynasty — the Persians under Cyrus generally did NOT do this to the Babylonian royal house, which was one reason the Persians were seen as unusually humane. The oracle's severity is the judgment's completeness.</p>",
    "22": "<p>'I will rise up against them, declares the LORD of hosts. I will cut off from Babylon its name and its survivors, its offspring and descendants, declares the LORD' — YHWH's direct first-person assertion against Babylon: 'I will cut off from Babylon name and remnant, offspring and posterity' (shem veshe'ar venim venekhed). The four categories (name, remnant, offspring, posterity) cover every form of continuity: present reputation (name), current survivors (remnant), immediate descendants (offspring/son), and future generations (posterity/grandson). Total discontinuity. The fourfold phrase mirrors the Davidic covenant's fourfold extension (2 Sam 7:12-16) inverted: where David's dynasty is promised name, throne, offspring, and perpetuity, Babylon's is promised only their elimination.</p>",
    "23": "<p>'I will make it a haunt for the hedgehog and turn it to stagnant marshes, and I will sweep what remains with the broom of annihilation, declares the LORD of hosts' — three images of complete desolation: (1) moresh qippod (possession of the hedgehog/bittern — a small marsh bird) — wild animal habitation of the abandoned city; (2) agmei-mayim (stagnant marshes/pools) — standing water in the ruins; (3) the 'broom of annihilation' (matate hashmid, the broom of destruction) sweeping out 'what remains' (she'arit, the remnant — there will be no remnant). The broom sweeping the land clean anticipates the final comprehensive cleansing. The stagnant marsh imagery fits historical Babylon (in the Tigris-Euphrates flood plain) but is also the desolation image of 13:20-22 extended. Revelation 18:2 applies similar imagery to eschatological Babylon: 'a haunt for every evil spirit.'</p>",
    "24": "<p>'The LORD of hosts has taken an oath: Exactly as I have planned, so it will happen; exactly as I have purposed, so it will stand' — the divine oath oracle: 'nishba YHWH tseva'ot, the LORD of hosts has sworn.' The divine oath is the highest form of divine commitment — what YHWH has sworn will certainly occur (Heb 6:17: 'to make the unchanging nature of his purpose very clear, God confirmed it with an oath'). 'As I have planned (dimiti), so it will happen (ken haya); as I have purposed (ya'atsati), so it will stand (ken taqum)' — the divine intention (dimah/ya'ats) is the guarantee of historical outcome. This oracle interrupts the Babylon taunt to apply the same principle of divine sovereignty to Assyria (v25): the same God who plans Babylon's fall plans Assyria's defeat in the land of Israel.</p>",
    "25": "<p>'I will crush the Assyrian in my own land; I will trample him on my mountains. His yoke will be lifted from my people and his burden taken from their shoulders' — the Assyrian oracle embedded in the Babylon section (possibly a second historical referent or the typological equation of all imperial oppressors). 'In my own land' (bear'tsi, in my land) and 'on my mountains' (beharai, on my mountains) — YHWH's territorial claim over the land of Israel means the Assyrian invasion is a trespass on divine property. The specific response to Sennacherib's invasion in 701 BCE (2 Kgs 19:35: the angel striking 185,000) fulfills this oracle. The yoke-and-burden imagery from 9:4 (the rod and yoke broken 'as on the day of Midian') returns as the description of what YHWH removes from his people's shoulders.</p>",
    "26": "<p>'This is the plan purposed for the whole earth, and this is the hand stretched out over all the nations' — the scope expansion from the Assyria-in-Israel focus to 'the whole earth' (kol-ha'arets) and 'all the nations' (kol-hagoyim). The 'plan' (ha'etsah, the counsel/plan — from ya'ats, to counsel) and the 'stretched out hand' (hayad hanetuyah, the extended hand) — the same 'outstretched hand' refrain that appeared four times in the judgment cycle of 9:12-10:4. But now YHWH's hand is extended not to punish Israel but over all nations who oppose his purpose. The cosmic scope: the divine plan for Israel's restoration and the nations' judgment is universal, not merely regional.</p>",
    "27": "<p>'For the LORD of hosts has made this purpose, and who can overturn it? His hand is extended, and who can force it back?' — two rhetorical questions about the irresistibility of divine purpose: 'who can overturn it?' (mi yefer, who can nullify/break?) and 'who can force it back?' (mi yashivennah, who can turn it back?). The rhetorical force is the divine sovereign's unchallengeability — no human power can reverse YHWH's plans or reverse his extended hand. Job 9:12 uses the same vocabulary: 'Who can say to him, \"What are you doing?\"' Isaiah 46:10 states the same principle: 'My purpose will stand, and I will do all that I please.' The un-overturnable divine plan is the theological foundation for both the judgment of Babylon and the restoration of Israel.</p>",
    "28": "<p>'In the year when King Ahaz died, this oracle came' — the chronological heading for the Philistia oracle (vv.28-32). Ahaz died around 715-727 BCE (the exact dates are debated; 715 BCE is the most widely accepted scholarly date for his death). The heading is the same formulaic structure as 6:1 ('in the year King Uzziah died') — connecting both oracles to key royal transitions. The Philistia oracle is addressed to Israel's western coastal neighbor, which had been in perpetual conflict with Israel and Judah (1 Sam 4-7, 14, 17, 31; 1 Chr 10; 2 Chr 26:6). Ahaz's death would have seemed an opportunity to Philistia — relief from Judean pressure — but the oracle declares this to be mistaken.</p>",
    "29": "<p>'Do not rejoice, O Philistia — none of you — because the rod that beat you down is broken. For from the serpent's root a viper will grow, and its fruit will be a darting, venomous serpent' — the warning against premature celebration: al-tismachi Peleshet kullekh (do not rejoice, all of Philistia). The 'rod that beat you' (maqqeh, the rod/striking) being broken — probably referring to a recent death or defeat of an Israelite or Judean king (Ahaz, or a military setback). But the snake imagery warns: from the root of the old threat grows a worse one. The three-stage escalation: serpent root (nachash) → viper (epheh, the desert viper, highly venomous) → flying venomous serpent (saraph me'ofef, the seraph/burning one that flies). Each stage is more dangerous. The flying serpent may refer to Assyria or Babylon, or to Hezekiah as a more formidable king who defeated Philistia (2 Kgs 18:8).</p>",
    "30": "<p>'The poorest of the poor will have pasture and the needy will rest in safety; but I will put your root to death with famine and your survivors will perish' — the contrasting fates: for Judah's poor, the messianic pastoral care ('the poorest of the poor will have pasture' — a shepherd image where even the lowest are provided for); for Philistia, 'I will put your root to death with famine' (veharaig bekara'v shorekh, and I will kill with famine your root) and 'your survivors will perish' (she'eritkha yaharog, your remnant he will slay). The contrast of the poor-of-Judah's security with Philistia's remnant-elimination uses the remnant vocabulary: Judah has a guaranteed remnant (the 'poorest of the poor' are safe), Philistia has no guaranteed remnant.</p>",
    "31": "<p>'Wail, O gate! Cry out, O city! Dissolve with terror, all of Philistia! For a column of smoke rises from the north and there is not one straggler in that advancing army' — the triple call to mourning: 'wail, O gate; cry out, O city' (heili sha'ar ze'aqi ir, wail O gate, cry out O city) and 'dissolve, all of Philistia' (namogu kol-Peleshet). The 'column of smoke from the north' (ki mitsafon ashan ba, for from the north smoke comes) is the standard image for the advance of a great army — the dust and smoke cloud of an army's approach visible from afar. 'Not one straggler in the advancing force' (ein boded bemo'adav, not one isolated/straggler in his appointed places) — a disciplined army with no weak links, no one lagging behind. The Assyrian army under Sennacherib (or Nebuchadnezzar later) fits this description of total discipline and overwhelming force.</p>",
    "32": "<p>'What answer will be given to the envoys of the nations? This: The LORD has established Zion, and in her the poor of his people will find their shelter' — the closing verse reframes the entire Philistia oracle: the answer to any inquiry about Zion's security is YHWH's establishment of it. 'The LORD has established Zion' (Yhwh yissad Tsiyon, YHWH has founded Zion) is the permanent foundation (yissad = laid the foundation, grounded). 'The poor of his people will find their shelter in her' (aniyei ammo yechesu-vah, the poor of his people will take refuge in her). The 'poor' (aniyim) of Judah who trust YHWH rather than military alliances or political scheming are the ones Zion shelters. The irony: Zion's security is guaranteed not by military strength but by divine foundation — which is precisely what the Philistines (and Assyrians) cannot comprehend or overturn.</p>"
  },
  "15": {
    "1": "<p>Isaiah 15:1 begins the Moab oracle (massa Moav, the burden/oracle of Moab), one of the most emotionally affecting of the burden-oracles (chs. 13-23). 'Because Ar of Moab is destroyed in a single night, Moab is ruined; because Kir of Moab is destroyed in a night, Moab is ruined' — the double destruction of Moab's two major cities, repeated with the same framing. Ar (possibly modern Rabbah of Moab) and Kir (Kir-hareseth/Kir-haresh, modern Kerak) were the two chief Moabite cities. The Mesha Stele (c. 840 BCE, discovered 1868) is crucial background: this Moabite royal inscription records the same cities (Nebo, Medeba, Ataroth, Jahaz — all appearing in Isaiah 15) and describes Moabite victories over Israel in the 9th century, showing the deep history of Moabite national identity that the oracle sees destroyed.</p>",
    "2": "<p>'The people go up to the temple and to Dibon, to the hilltop shrines to weep; they wail over Nebo and over Medeba — every head shaved bald and every beard cut off' — the mourning rites: going to the temple (beit, the house) and Dibon (the Moabite capital and major cult center, mentioned in the Mesha Stele as a place where Mesha built a high place for Chemosh). The hilltop shrines (bamot, the high places scattered across the land) are sites of lamentation. Nebo (Mount Nebo, where Moses died — Deut 34:1-5 — and the city of Nebo, a Moabite town) and Medeba (a town in the Moabite plateau, also mentioned in Mesha Stele) are the objects of mourning. The mourning rites: shaved heads (qorchah, bald-headness) and cut beards (gazuzah, clipped) were standard ANE mourning practices (Isa 22:12; Jer 48:37; Mic 1:16) — deliberately disfiguring the body in grief.</p>",
    "3": "<p>'In the streets they wear sackcloth; on the rooftops and in the public squares everyone mourns and weeps uncontrollably' — the pervasive mourning in every social space: in the streets (bechutsehotav) wearing sackcloth (saq, the rough burlap mourning garment — cf. Gen 37:34, David mourning; 2 Kgs 19:1, Hezekiah in sackcloth). On the rooftops (begagot) and in the public squares (birechovot) — the two spaces of Moabite daily social life, public and accessible, both filled with weeping. 'Everyone weeps uncontrollably' (yered bivechi, going down in weeping = dissolving into tears). The communal totality of the mourning — no private grief here but a whole nation's public lamentation — reflects the magnitude of the disaster.</p>",
    "4": "<p>'Heshbon and Elealeh raise their cry — it can be heard all the way to Jahaz. At this even Moab's soldiers cry out; each one shudders within' — the sound of lamentation spreading across the Moabite plateau: from Heshbon (the major city of northern Moab, formerly Sihon's capital, Num 21:25-26) and Elealeh (modern el-Al, near Heshbon) the cry can be heard as far as Jahaz (a city in the Moabite plateau, Num 21:23 — the site where Israel defeated Sihon). The sound-geography traces the extent of the disaster by how far the lamentation can be heard. Even the halutzei-moav (the soldiers/armed men of Moab, those trained not to show emotion) cry out and 'each one shudders within' (nafesho yare'ah lo, his soul/life trembles within him).</p>",
    "5": "<p>'My heart cries out for Moab. Her fugitives flee to Zoar, to Eglath-shelishiyah. At the climb up Luhith they go up in tears; on the Horonaim road they raise a desperate cry of ruin' — the prophet's compassion for Moab: 'my heart cries out for Moab' (libbi leMenua yezeaq, my heart cries out for Moab) — unprecedented prophetic empathy in a judgment oracle. Isaiah is not triumphant over Moab's fall but genuinely grieved. The refugee route traced: fleeing south to Zoar (the southernmost city, near the Dead Sea, where Lot fled from Sodom, Gen 19:22-23), to Eglath-shelishiyah ('the third heifer,' probably a place name), up the ascent of Luhith, down the Horonaim road — tracing the desperate flight south along the King's Highway through Moab.</p>",
    "6": "<p>'For the pools of Nimrim have dried up; the grass is withered, the new growth is gone, there is nothing green left' — the ecological dimensions of the judgment: the pools/waters of Nimrim (me Nimrim — probably near the Dead Sea in southern Moab) are dried up (ki me Nimrim lishamamot yihyu, for the waters of Nimrim will be desolations). The water source failure produces complete ecological collapse: the grass (deshe, the tender new grass) is withered, the vegetation (esev, herbage) is done (chalah, ended/finished), all green (yerakon, every green plant) is gone. The drying of water sources in a pastoral society is total economic collapse — livestock cannot survive, agriculture fails, human habitation becomes impossible. The ecological failure mirrors the social/military collapse described in vv.1-5.</p>",
    "7": "<p>'So whatever they have accumulated and saved they carry away across the Brook of the Willows' — the refugee economy: 'al-ken yitrah ashu vipiqudam, therefore the surplus they made and their stores they carry' (everything accumulated over generations) al-nachal ha'aravim yisaum (over the Brook of the Willows they carry them). The Brook of the Willows is probably the Wadi el-Hesa (ancient Zered, Num 21:12; Deut 2:13-14) — the southern boundary of Moab, crossing which means entering Edomite territory. The refugees carry their material wealth in flight — the savings of generations reduced to what can be physically transported by refugees fleeing south.</p>",
    "8": "<p>'The sound of weeping has encircled the whole border of Moab — the wailing reaches Eglaim, the wailing reaches Beer-elim' — the geographic totality of lamentation: the wailing (ze'aqah, the cry/shriek) has surrounded (hiqqifah, encircled) Moab's entire border. The two endpoints of the border-circuit: Eglaim (in the south, possibly modern Rujm el-Gheilemeh) and Beer-elim (Well of the Mighty Ones, possibly near the northern border). The lamentation encircles the entire territory — there is no place within Moab's boundaries that has escaped the sound of mourning. The complete geographic perimeter of grief corresponds to the complete geographic scope of the disaster.</p>",
    "9": "<p>'For the waters of Dimon run red with blood; and I will bring more upon Dimon — a lion against the fugitives of Moab and against what remains of the land' — the bloody conclusion to the Moab oracle: the waters of Dimon (probably the same as Dibon, with a wordplay — Dimon sounds like dam = blood in Hebrew, creating 'the waters of Bloodville run red with blood'). The intensification: 'I will add upon Dimon more' (ostif al-Dimon, I will add more upon Dimon) — a 'lion' (aryeh, the lion) against the fugitives and the remnant. The lion as YHWH's agent of final judgment against those who escaped the initial military defeat — no escape route is safe. The Moab oracle ends on this note of no-refuge, which makes the appeal to Zion in 16:1-5 the only possible response.</p>"
  },
  "16": {
    "1": "<p>'Send the tribute lamb to the ruler of the land, dispatched from Sela across the desert to the mount of Daughter Zion' — the opening of ch.16 responds to the disaster of ch.15: the advice to Moab is to submit, send tribute, and seek shelter from Zion. 'Send a tribute lamb to the ruler of the land' (shilchu-kar moshlei erets misela, send a tribute-lamb to the ruler of the land from Sela) — kar (lamb) was a standard tribute commodity in the ancient Near East. The Mesha Stele records that Mesha of Moab paid tribute to Israel's king of 100,000 lambs and 100,000 rams' wool (2 Kgs 3:4). 'From Sela' (misela, from the rock/Sela) — either a Moabite city name ('the rock') or the fortress city of Petra in Edom (if Moabite refugees fled south). The tribute goes to 'Daughter Zion' (bat-Tsiyon, the personified Jerusalem) — submit to YHWH's city rather than trust in national pride.</p>",
    "2": "<p>'The women of Moab will be like a fluttering bird, like scattered nestlings, stranded at the fords of the Arnon' — the refugee image: Moabite women as a fluttering bird (of tsippor noded, like a wandering/flying bird) and 'scattered nestlings' (kaqqen nodad, like a nest scattered/overthrown). The Arnon River (modern Wadi Mujib) was Moab's northern boundary — the fords across the Arnon were the crossing point between Moabite and Israelite territory. The image is of panicked birds displaced from their nest — the ordinary settled life of Moab's population disrupted by the violence of conquest. The women specifically are highlighted — the most vulnerable in military conquest.</p>",
    "3": "<p>'Offer counsel, dispense justice; make your shade as dark as midnight at midday; shelter the refugees; do not betray the one who is fleeing' — the appeal to Judah (or possibly to the Moabites themselves urging cooperation with Judah): four imperatives: bring counsel (havi'u etsah, bring counsel/advice), dispense justice (asu mishpat, execute justice), make your shade/shadow like the night (shiti chalilah tsillekh betoch-tsaharayim, make your shade like night at noon — provide complete shelter even in daytime). 'Do not betray the one who is fleeing' (al-tegallit noded) — the covenant of asylum that protects refugees. The language of asylum and sheltering the fugitive reflects the ANE custom of sanctuary — even enemies could claim protection in certain sacred contexts.</p>",
    "4": "<p>'Let my displaced people take shelter with you; be a refuge for them from the ravager. For the tyrant is gone, destruction is over, and the one who trampled is out of the land' — the appeal for refuge: 'let my displaced people dwell in you' (yaguru vekha niddachai Moav, let the outcasts of Moab sojourn with you) — the Moabite refugees taking shelter in Judah. This situation may have a specific historical referent: Moabite refugees fleeing to Judah during Assyrian campaigns. The eschatological dimension: 'for the tyrant (mits) is gone, destruction (shadud) is over, the trampler (roames) has ceased out of the land' — the oppressor has ended and shelter is now possible. This may anticipate the post-Assyrian/Babylonian restoration when the immediate military threat is past.</p>",
    "5": "<p>'Then a throne will be set up in covenant faithfulness; one will sit on it in truth in the tent of David — one who judges and actively pursues justice and is swift to act with righteousness' — the messianic throne promise embedded in the Moab oracle: 'vekon bechesed kise, then a throne will be established in loyal-love/covenant-faithfulness.' The throne set up in chesed (the covenantal love/loyalty of the Davidic covenant, 2 Sam 7:15: 'my lovingkindness [chesed] will never be taken away from him') and veeshav alav be'emet (one will sit on it in truth/faithfulness). 'In the tent of David' (be'ohel David) — the tabernacle/dwelling of David, the Davidic dynasty's enduring promise. The specific qualities: judging (shofet), pursuing justice (mevaqesh mishpat), swift to righteousness (mehir tsedaqah). Amos 9:11 also promises the restoration of 'David's fallen tent.' Acts 15:16-17 cites this in the context of Gentile inclusion — the tent of David restored to include all nations.</p>",
    "6": "<p>'We have heard of Moab's arrogance — his immense pride, his haughtiness and conceit and fury — his empty boasting amounts to nothing' — the grounds for Moab's judgment stated plainly: shama'nu ge'on-Moav ge'eh meod (we have heard of Moab's pride — he is very proud), his gaavah (arrogance), gee'ut (pride/haughtiness), evra (overflow of anger/fury), and his baddav lo-ken (his empty boastings — baddim = empty/vain things, threads = empty boasts). Moab's specific sin is pride — the same sin as Babylon (ch.13-14) but in a smaller nation. The Moabite national pride recorded in the Mesha Stele ('Chemosh has given me victory over Israel') is the background for this charge of divine-dismissing self-confidence.</p>",
    "7": "<p>'So let Moab wail over Moab — let everyone wail; mourn, utterly stricken, over the loss of Kir-hareseth' — the universal mourning commanded: yeylelil Moav leMenua, let Moab wail for Moab (the nation mourning for itself). The specific lament for Kir-hareseth (the great fortified city of Moab, modern Kerak — a massive hilltop fortress that controlled the south Moabite plateau). The phrase 'ashishei Kir-chareseth tahegas umadovim yileku (for the raisin-cakes of Kir-hareseth you will be stricken, altogether devastated)' — the specific agricultural product (raisin-cakes, ashishot, pressed grape-cakes used in feasting and possibly cult worship) of the region destroyed. The specificity grounds the mourning in concrete economic and cultural loss.</p>",
    "8": "<p>'For the terraces of Heshbon have withered; the vine of Sibmah — whose branches once stretched as far as Jazer, wandered through the desert, and reached to the sea — its finest vines have been struck down by the rulers of the nations' — the vine of Sibmah (the famous wine-producing area of Moab, northwest of Heshbon) is one of the great OT images of prosperity destroyed. The vine's extraordinary extent is described: reaching to Jazer (north), wandering through the desert (east), reaching to the sea (the Dead Sea, west) — the vine covered the entire Moabite plateau in its prime. Jeremiah 48:32 quotes this verse almost verbatim in his Moab oracle ('I weep for you, O vine of Sibmah, more than I weep for Jazer'), showing the influence of Isaiah's Moab oracle on later prophetic tradition. The 'rulers of the nations' who cut down the vines = Assyrian or Babylonian military campaigns that stripped the productive land.</p>",
    "9": "<p>'I weep for the vine of Sibmah with the tears of Jazer; I drench you with my own grief, O Heshbon and Elealeh — because the war cry has crashed down over your summer harvest and ripe grapes' — the prophet's direct personal mourning resumed (cf. 15:5): 'al-ken evkeh bivchi Yazer gehen Sivmah, therefore I weep with the weeping of Jazer for the vine of Sibmah.' The prophet soaks Heshbon and Elealeh with his tears (artivekh, I will drench you). The specific agricultural loss: the harvest shout (heydad, the joy-cry of the harvest) has fallen on the summer fruit (qayits) and the vintage (batsir). The harvest shout is the sound of agricultural celebration (Jer 25:30 uses it for divine judgment: YHWH shouting a heydad against his vineyard). The joy-cry of the harvest has become the cry of destruction.</p>",
    "10": "<p>'Gladness and joy have been stripped from the orchards; in the vineyards no one sings, no one shouts for joy; no one treads grapes in the winepresses. I have silenced the harvest songs' — the negation of harvest celebration: 'gladness and joy' (simcha vegil) 'have been stripped' (ne'esaf, gathered away — the harvest verb ironically applied to the stripping of joy). The vineyard-silence contrasts with the normal harvest scenes of Ps 65:11-13 (the pastures clothed with flocks, the valleys covered with grain, shouting and singing). 'No one treads grapes in the winepresses' (lo yidrok hayoqev) — the wine-pressing tread was communal celebration, accompanied by singing (Jer 25:10: 'I will banish the sounds of joy and gladness'). 'I have silenced the harvest songs' (heydad hishbatti, I have caused the harvest-shout to cease).</p>",
    "11": "<p>'My heart resonates like a lyre in mourning for Moab; my deepest self aches for Kir-hareseth' — the deepest expression of the prophet's grief: 'al-ken me'ai leMenua yehemdayun, therefore my bowels/inner parts sound like a lyre/harp for Moab.' The me'ayim (bowels/inner parts) were in Hebrew physiology the seat of deep emotion — the churning interior of grief sounds like the resonance of a lyre (kinnor = the lyre, the instrument of both joy and lament). The 'deepest self' (kirbi, my inner parts) aches for Kir-hareseth. The prophet's grief is visceral and musical — the body as a resonating instrument of compassion for the enemy nation's suffering. This is one of the OT's most remarkable expressions of prophetic empathy for a foreign people under divine judgment.</p>",
    "12": "<p>'When Moab shows himself at the high place, wears himself out in prayer, and comes to his sanctuary to plead, he will not succeed' — the futility of Moab's cultic response: appearing at the high place (bamah, the local hilltop shrine), 'wearing himself out' (vnilah, and he will tire himself out) in worship, and coming to the sanctuary (miqdash, the holy place) to intercede (hitpallel, pray/intercede). But 'lo yukal' (he will not be able/succeed). Moab's god Chemosh (mentioned in the Mesha Stele; 1 Kgs 11:7 calls him the 'detestable god of Moab') cannot deliver what YHWH has decreed. The futility of pagan worship in the face of YHWH's judgment is a recurring prophetic theme (10:10-11; 46:1-2). The specific futility of Moab's sanctuary worship connects to the contemptuous dismissal of Babylon's deities in chs. 40-48.</p>",
    "13": "<p>'This is the word the LORD pronounced concerning Moab in the past' — the editorial note connecting the oracle to an earlier prophetic word (deborah, the older oracle). The phrase 'me'az' (from that time, in the past) indicates that what precedes (15:1-16:12) is an older prophetic tradition, and what follows (v14) is a fresh, more specific word with a timeline. This kind of editorial layering (older oracle + new specific application) is characteristic of the prophetic books — Jeremiah 48 similarly reworks the Isaiah Moab oracle with additions. The notation preserves the history of prophetic tradition while adding contemporary application.</p>",
    "14": "<p>'But now the LORD declares: Within three years — no more than the term of a hired labourer — Moab's glory will be brought into contempt, for all its vast numbers; what is left will be very small and of no account' — the specific timeline: 'beshalosch shanim kishne sakir, in three years as the years of a hired laborer.' The hired laborer's term (sakir) was a fixed legal period — the comparison emphasizes exactness and certainty rather than vagueness. 'Within three years, no more' — 'lo yikkabed' (the glory will not be heavy/honored). Moab's 'vast numbers' (hamun rav, the great multitude) reduced to 'very small and of no account' (me'at mitsar). The time-specific oracle is a test of prophetic reliability (Deut 18:21-22: 'if a prophet speaks in YHWH's name but the thing does not happen — he spoke presumptuously'). The precision of '3 years like a hired worker's term' is a datable claim.</p>"
  },
  "17": {
    "1": "<p>Isaiah 17:1 opens the oracle against Damascus: 'Behold, Damascus is about to cease being a city; it will become a pile of rubble' (hineh Damascus mussar me'ir vehayethah me'i medurah, behold Damascus will be removed from being a city and will become a heap of rubble). The oracle connects to the Syro-Ephraimite crisis of 735-732 BCE — Damascus was the capital of the Aramean (Syrian) kingdom under Rezin, who allied with Pekah of Israel against Judah (7:1-6). Tiglath-Pileser III destroyed Damascus in 732 BCE (2 Kgs 16:9: 'The king of Assyria attacked Damascus and captured it; he deported its inhabitants to Kir and put Rezin to death'). The oracle is thus accurately predictive from Isaiah's perspective, or contemporaneous with the event if composed during the 732 BCE campaign.</p>",
    "2": "<p>'The towns of Aroer are abandoned — left for flocks to graze, and they will lie down there with no one to disturb them' — the depopulation imagery: the towns of Aroer (Aro'er, a town on the Arnon River in Moab/Ammon — or possibly a town in the Damascus/Syria region) abandoned and left for flocks (la'adarim, for herds). Pastoral nomads and their flocks occupying the ruins of formerly prosperous cities is the standard desolation image (13:20; 34:13-15). 'No one to disturb them' (ein macharid, no one making them afraid) echoes Mic 4:4 ('every man will sit under his own vine... with no one to make them afraid') — the eschatological peace inverted as the peace of abandonment rather than fruitful security.</p>",
    "3": "<p>'The fortified city will disappear from Ephraim and the royal power from Damascus; and what remains of Syria will share the same fate as the diminished glory of the Israelites, declares the LORD of hosts' — the allied powers judged together: Ephraim (the Northern Kingdom, ally of Damascus) loses its fortified cities (mibtsar meEfraim, the stronghold from Ephraim), Damascus loses its royal sovereignty (memamlekhet miDammaseq, the kingdom from Damascus). The remnant of Syria (she'ar Aram, what is left of Syria) will be 'like the glory of the children of Israel' — the same fate, the same diminishment. The Syro-Ephraimite alliance that threatened Judah in 735-732 BCE falls together. 2 Kgs 15:29 records Tiglath-Pileser's deportation of northern Israelites, and 2 Kgs 16:9 records Damascus's fall.</p>",
    "4": "<p>'In that day the splendour of Jacob will fade and his well-nourished frame will waste away' — Jacob (the Northern Kingdom/Israel) described through two images of prosperity eroded: kevod Ya'aqov yidal (the glory/weight of Jacob will be made thin/lean) and mishman besaro yiraze (the fatness of his flesh will grow lean). The 'well-nourished frame' (mishman basar, the fat/richness of his flesh) — the prosperity of the Northern Kingdom under Jeroboam II (784-753 BCE) was exceptional (Amos 6:4-6 describes the luxury of the Samarian elite: beds of ivory, choice lambs, fine wine, the best oils). This prosperity is what 'wastes away' under divine judgment. The lean-and-thin language is the antithesis of the covenant blessings of Deut 32:15 ('Jeshurun grew fat and kicked — fat and bloated and gorged').</p>",
    "5": "<p>'It will be like a reaper sweeping in the grain, gathering up the ears with his arm — like someone gleaning what is left in the Valley of Rephaim' — the gleaning imagery for what remains of Israel after judgment: 'like the reaping of standing grain' (ke'asof qatsir), gathering the ears with one arm while the other cuts. The Valley of Rephaim (emeq Refa'im) was the fertile grain-producing valley southwest of Jerusalem (2 Sam 5:18; 23:13), famous for its harvests. The comparison: the judgment of Israel leaves only 'gleanings' (like a harvested field with a few stalks left). The gleaning theology connects to Ruth 2:2-7 (the gleaning laws of Lev 19:9-10 provide for the poor from the edges of harvested fields) — what remains is the deliberate remnant left for the vulnerable.</p>",
    "6": "<p>'Only gleanings will remain, as when an olive tree is beaten — two or three olives at the very top of the highest branch, four or five on the outlying boughs — declares the LORD, the God of Israel' — the olive-beating image specifies the remnant's smallness: when an olive tree is beaten (ke'nofesh zayit, like the beating/threshing of an olive tree) a few olives remain at the top (rosh amir, the top of the branch) — two or three — and 'four or five on its productive boughs' (bisfiyoteha poreiyah, on its fruitful branches). The numbers (2-3, 4-5) emphasize smallness without specifying exact numbers — a 'very few.' This is the remnant theology in its most concrete form: not a comfortable minority but a barely-surviving handful. The 'YHWH God of Israel' title at the verse's end (ne'um Yhwh Elohei Yisrael) is the one who both brings the judgment and preserves the tiny remnant.</p>",
    "7": "<p>'In that day people will look to their Creator, and their eyes will be fixed on the Holy One of Israel' — the theological reversal produced by judgment: 'yisheh ha'adam al-osohu, in that day the man/people will look to his Creator' (yisheh = direct attention/gaze to; osohu = his maker, the one who made him). The judgment that strips away the prosperity and military alliances also strips away the religious substitutes, leaving only the gaze toward YHWH. 'Holy One of Israel' (Qedosh Yisrael) is Isaiah's signature divine title (26 occurrences in Isaiah). The verse functions as the positive interior of the judgment: the outcome of stripping is not annihilation but restored vertical focus. Hosea 2:14-16 expresses the same theology: YHWH strips Israel of her lovers so that she will call him 'my husband' again.</p>",
    "8": "<p>'He will have no regard for the altars he made, or for the Asherim poles or incense altars that his own hands fashioned' — the religious reform that judgment produces: 'he will not look toward the altars' (lo yisheh el-hamizbekhot, he will not look toward the altars) — specifically 'the altars he made' (ma'aseh yadaiv, the work of his hands). The Asherim (asheirim, plural of Asherah) are the wooden poles or sacred trees associated with the Canaanite goddess Asherah, consort of El in Canaanite religion and frequently mentioned as a cultic object in Israelite worship until Josiah's reform (2 Kgs 23:4, 6, 14-15). The chammanim (incense altars, sun-pillars) were aromatic incense platforms. All these hand-made religious objects are abandoned as the 'look to the Creator' begins. Isa 2:20 uses the same vocabulary of discarding idols when YHWH arises in judgment.</p>",
    "9": "<p>'In that day their fortified cities will be like abandoned woodland shrines and deserted hilltops that were left vacant before the Israelites — utter desolation' — the desolation of Israel's fortified cities (mivtsar) compared to the abandoned pre-Israelite Canaanite shrines (ma'aseh hachoresh vehaamir, the work of the woodland/thicket and the summit) that the Israelites found when they entered the land (lifnei venei Yisrael, before the children of Israel — meaning left by the earlier inhabitants). The comparison is precise: as the Canaanites abandoned their cultic sites when Israel arrived, so Israel's own fortified cities will be abandoned under divine judgment. The cycle of dispossession that began with the Canaanites now encompasses unfaithful Israel.</p>",
    "10": "<p>'For you have forgotten the God who saves you and have not remembered the Rock who shelters you; so you plant ornamental gardens and set in shoots from foreign vines' — the theological cause of the judgment: shakhacht Elohei yish'ech (you have forgotten the God of your salvation) and tsur ma'uzekh lo zachart (the Rock of your refuge you have not remembered). The 'God of salvation' and 'Rock of refuge' are covenant titles from the Song of Moses (Deut 32:4, 15, 18, 30, 31) and the Psalms (Ps 18:2; 28:1; 31:2-3; 62:7). The response to forgetting God: planting 'ornamental gardens' (na'amanim, pleasant/beautiful gardens) and 'foreign vine shoots' (zemoroth zar, cuttings of a strange-god/alien vine). These may be pagan fertility gardens (the 'gardens of Adonis' — forcing plants in shallow soil that bloom and die quickly — known in the Hellenistic period but possibly earlier) or agricultural idolatry linked to Canaanite fertility religion.</p>",
    "11": "<p>'Though you force them to sprout the very day you plant them and blossom the morning you sow — yet come the day of grief and desperate pain the harvest will be gone' — the failure of forced agricultural idolatry: 'beyom natekh tegadali uvevoqer zar'ekh tafrihi, on the day you plant them you will make them grow, and in the morning when you sow they will sprout' — the human attempt to force immediate results (suggesting magical/cultic agricultural practices designed to compel divine blessing). But 'the harvest will be gone' (nad qatsir beyom nachalah uke'ev anush, the harvest flees on the day of grief and desperate pain). The forced bloom that cannot sustain — the idolatrous quick-fix that produces no lasting harvest. The 'day of desperate pain' (uke'ev anush, and incurable pain) when the harvest fails is the judgment day that the artificial gardens cannot avert.</p>",
    "12": "<p>'Woe — the uproar of many peoples! They roar like the roaring of the seas! And the crashing of nations — they crash like the surge of mighty waters!' — the cosmic sound-image for the nations' advance: 'hoy hamon ammim rabbim, woe — the sound of many peoples who sound/roar like the roaring of the seas (kehamon yammim yehemayun) and the crashing of leummim (national groups) who crash like the crashing of mighty waters (kemishbar mayim kabirim yishsaun).' The sea-roar as military advance image: the unstoppable, consuming force of the enemy army rendered as the sound of ocean surf. The nations' 'uproar' (hamon) is both the sound and the mass of the force. Isaiah uses the sea-roar image for the Assyrian advance in 8:7-8 (the rising River Euphrates = Assyria's overflow).</p>",
    "13": "<p>'The nations surge like surging water — but he rebukes them and they scatter far away, driven like chaff off the mountains before the wind, like a dust cloud spinning away before the gale' — the sudden reversal by divine rebuke: 'umim keshon mayim rabbim yishsaun, but the peoples will roar like surging mighty waters — vegaar bo veneas memerchaq (but he will rebuke it and it will flee far away).' The divine rebuke (ga'ar, the sound/word of divine authority — Ps 18:15: 'at your rebuke, O LORD, at the blast of the breath of your nostrils') instantly disperses what seemed like an irresistible force. The two similes for the instant scattering: chaff before the wind on the mountains (kemo motz harim lifnei-ruach, like chaff of the mountains before wind) and a dust-cloud/tumbleweed before a storm (ukegalgal lifnei sufah, like a wheel/tumbleweed before a storm).</p>",
    "14": "<p>'Evening comes — sudden terror. Before morning, there is nothing left. This is the destiny of those who loot us, the fate reserved for those who plunder us' — the 'evening terror, morning nothing' time-sequence: 'le'et erev vehinneh balahah, toward evening and behold — sudden terror; before morning they are gone (ainen).' The historical referent: the angel of YHWH striking 185,000 Assyrian troops in the night of Sennacherib's siege of Jerusalem (2 Kgs 19:35; Isa 37:36). The Assyrian camp full and threatening at evening; by morning 'all of them were dead bodies.' The verse 14b is a community formula: 'this is the portion of those who despoil us and the lot of those who plunder us' (ze chelek shoseinu vegoral levezeinu) — affirming the theological pattern applies to all who threaten YHWH's people. Psalm 46:5 expresses the same theology: 'God will help her at the break of dawn.'</p>"
  },
  "18": {
    "1": "<p>Isaiah 18 opens the oracle about Cush (Ethiopia/Nubia): 'Woe to the land buzzing with wings beyond the rivers of Cush' (hoi erets tsiltsal kenafayim asher me'ever lenehare-Kush, woe O land of whirring/buzzing of wings that is beyond the rivers of Cush). The 'buzzing with wings' (tsiltsal kenafayim, the buzzing-insect sound of wings) may refer to the abundant insects of the Nile region (locusts, flies — cf. 7:18-19 where YHWH whistles for Egypt's flies), or to the sound of swift messengers' feet, or to the sails/wings of the river craft. 'Beyond the rivers of Cush' (me'ever lenehare-Kush) — the land south of Egypt's Nile branches. During Isaiah's time (725-700 BCE), Egypt was ruled by the 25th Dynasty of Cushite/Nubian pharaohs: Piankhi/Piye (747-716), Shabaka (716-702), Shebitku (702-690), and Taharqa (690-664). 'Cush' thus refers to the rulers of both Nubia and Egypt.</p>",
    "2": "<p>'It sends envoys by sea, in papyrus boats skimming the waters. Go, swift messengers, to a people tall and smooth-skinned, dreaded everywhere near and far — a mighty, dominating nation whose land is cut by rivers' — the Cushite envoys described: 'boshilach bayam tzirim uvekhele-gome, who sends envoys by sea, in papyrus vessels.' The papyrus boats (kele-gome, vessels of papyrus reed) were the characteristic Nile craft — light, fast, made from bundled papyrus. The description of the Cushites: 'tall and smooth-skinned' (memushshak umorah, smooth/sleek of skin), 'feared from near and far' (nora min-hu umehala'ah, feared from it and from afar), 'a mighty, dominating nation' (goi qav-qav umevusah, a line-measuring and trampling nation — meaning one that measures out territory and crushes resistance), 'whose land rivers divide' (asher baze'u nehroth artso, whose land rivers have cut/divided). The Nile and its branches created the geography of Nubia/Egypt.</p>",
    "3": "<p>'All inhabitants of the world and all who dwell on earth — when a signal is hoisted on the mountains, look! When a trumpet is sounded, listen!' — the universal attention summoned: YHWH issues a call to the entire world (kulkhem yoshevei tevel veshokhnei erets, all you who dwell in the world and you who dwell on earth). The two signals: a nes (banner/signal) raised on the mountains — look! A shofar (ram's horn, the trumpet of assembly and alarm) — listen! The signal-and-trumpet combination is the standard military and prophetic assembly call (5:26: YHWH lifting a banner and whistling for the nations; Joel 2:1: 'Blow the trumpet in Zion, sound the alarm on my holy mountain'). All nations are being called to witness what YHWH is about to do regarding the Cushite-Egyptian power that the envoys represent.</p>",
    "4": "<p>'For this is what the LORD said to me: I will stay quiet in my dwelling place and watch — like shimmering heat in the bright sun, like a cloud of dew in the heat of harvest' — the divine posture of quiet watching: 'ki koh amar YHWH elai, for thus the LORD said to me.' YHWH's description of his own posture: eshqotah ve'abbitah vimekoniy, 'I will be quiet and watch in my dwelling place.' The two similes for YHWH's barely-perceptible-yet-present posture: (1) 'like shimmering heat over clear light' (kecham tsach al-or, like heat in clear sunlight — the desert heat shimmer barely visible but definitely present); (2) 'like a cloud of dew in the heat of harvest' (ke'av tal bechor qatsir, like a cloud of dew in the heat of harvest — the early morning dew-mist barely visible as vapor before the sun burns it off). YHWH is not absent — he watches — but does not immediately intervene. This posture of divine patience before sudden intervention is the theological key to 701 BCE (Sennacherib's army at Jerusalem, then overnight destruction).</p>",
    "5": "<p>'For before the harvest, once the blossom is done and the flower turns into a maturing grape, he will trim off the shoots with pruning knives and strip away and cut down the spreading branches' — the agricultural timing of divine intervention: 'ki lifnei qatsir kethom perach, for before the harvest when the blossom is finished.' The exact moment: when the blossom (perach) is over and the flower (nitsah) becomes a maturing/ripening grape (boser gomel, the sour-grape that is ripening). At the precise moment of near-maturity — the Cushite/Assyrian threat is fully developed and about to strike — YHWH acts: 'yikrath hazelazlim bemazemoroth veeth-hanesisim heser yatzil, he will cut the branches with pruning knives and the spreading branches he will strip away and cut down.' The vineyard imagery (YHWH as vinedresser, ch. 5:1-7; 27:2-6) applied to geopolitical pruning: the threatening power cut at the moment of apparent triumph.</p>",
    "6": "<p>'They will all be abandoned to the mountain birds of prey and to the wild animals; the birds will summer on the carcasses and the beasts will winter on them' — the aftermath of divine pruning: the cut branches (the Cushite/Assyrian forces) left for the birds and beasts. 'They will be abandoned together' (ye'azvu yachdav) to the birds of prey of the mountains (le'ayit harim) and to the beasts of the land (velivhemeth ha'arets). The seasonal cycle of scavenging: 'the birds will summer on them' (veyatitz alehem ha'ayit, the summer-prey bird will summer on them) and 'all the beasts of the land will winter on them' (kol-behemat ha'arets alehem tacharopenah, all the beasts will winter on them). The historical referent is the Sennacherib defeat of 701 BCE — 185,000 soldiers left as carcasses overnight (2 Kgs 19:35), then the 'summer' and 'winter' scavengers completing the process.</p>",
    "7": "<p>'At that time a tribute offering will be brought to the LORD of hosts from the tall and smooth-skinned people — the nation feared everywhere, the mighty and dominating people whose land the great rivers divide — to Mount Zion, where the LORD of hosts has placed his name' — the oracle's positive conclusion: the judgment on Cushite power (expressed in vv.5-6) leads to Cush voluntarily bringing tribute to YHWH at Zion. 'Ba'et hahi yuval-shay laYHWH tseva'ot, at that time a gift will be brought to the LORD of hosts' from the very people described in v2 (tall and smooth-skinned, feared, mighty, divided-by-rivers). The voluntary tribute from Egypt/Cush to Zion fulfills Ps 68:31 ('princes come from Egypt; Cush will stretch out her hands to God') and Ps 87:4 (Cush among those registered as knowing YHWH). The final destination: 'el har Tsiyon meqom shem YHWH tseva'ot, to Mount Zion, the place of the name of the LORD of hosts' — the ingathering of nations to YHWH's dwelling.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
